import sys
import json
from pathlib import Path

knowledge_dir = Path(sys.argv[1])
keywords = sys.argv[2:]
keywords_lower = [kw.lower() for kw in keywords]

results = {}
for json_path in sorted(knowledge_dir.rglob("*.json")):
    try:
        data = json.loads(json_path.read_text(encoding="utf-8"))
    except Exception:
        continue
    if data.get("no_knowledge_content"):
        continue
    rel_path = json_path.relative_to(knowledge_dir).as_posix()
    for sec in data.get("sections", []):
        sid = sec.get("id", "")
        if not sid:
            continue
        title = sec.get("title", "").lower()
        content = sec.get("content", "").lower()
        for kw in keywords_lower:
            if kw in title or kw in content:
                results.setdefault(rel_path, []).append(f"{sec['title']} ({sid})")
                break

for path, secs in sorted(results.items()):
    print(f"{path}")
    for s in secs[:3]:
        print(f"  - {s}")
